import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.BbQrW5_t.js";const u=JSON.parse('{"title":"第五章 中学发展心理","description":"","frontmatter":{"title":"第五章 中学发展心理","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter5.md","filePath":"study/teacher-cert/education-knowledge/chapter5.md","lastUpdated":1783652711000}'),h={name:"study/teacher-cert/education-knowledge/chapter5.md"};function o(l,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第五章-中学发展心理" tabindex="-1">第五章 中学发展心理 <a class="header-anchor" href="#第五章-中学发展心理" aria-label="Permalink to &quot;第五章 中学发展心理&quot;">​</a></h1><blockquote><p>本章考情：选择+简答，约 8-10 分 重点：皮亚杰认知发展、埃里克森人格发展、情绪情感</p></blockquote><hr><h2 id="_5-1-中学生认知发展-🔴🔴" tabindex="-1">5.1 中学生认知发展 🔴🔴 <a class="header-anchor" href="#_5-1-中学生认知发展-🔴🔴" aria-label="Permalink to &quot;5.1 中学生认知发展 🔴🔴&quot;">​</a></h2><h3 id="皮亚杰认知发展阶段-🔴🔴🔴" tabindex="-1">皮亚杰认知发展阶段 🔴🔴🔴 <a class="header-anchor" href="#皮亚杰认知发展阶段-🔴🔴🔴" aria-label="Permalink to &quot;皮亚杰认知发展阶段 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>年龄</th><th>特点</th><th>关键概念</th></tr></thead><tbody><tr><td>感知运动阶段</td><td>0-2岁</td><td>通过感知和动作认识世界</td><td>客体永久性 🔴</td></tr><tr><td>前运算阶段</td><td>2-7岁</td><td>自我中心、不可逆</td><td>泛灵论、自我中心 🔴</td></tr><tr><td>具体运算阶段</td><td>7-11岁</td><td>可逆、守恒</td><td>守恒 🔴、去自我中心</td></tr><tr><td>形式运算阶段 🔴</td><td>11岁+</td><td>抽象思维、假设演绎推理</td><td>命题推理、假设演绎</td></tr></tbody></table><p><strong>关键概念</strong> 🔴🔴：</p><ul><li><strong>客体永久性</strong>：知道不在眼前的物体仍然存在</li><li><strong>守恒</strong>：理解物体外观改变但量不变（如水倒入不同杯子水还是一样多）</li><li><strong>自我中心</strong>：认为别人看到的世界和自己一样（三山实验）</li></ul><p><strong>辨析题</strong> 🔴：</p><ul><li>&quot;中学生处于具体运算阶段&quot; → ❌ 中学生（11岁+）处于形式运算阶段</li></ul><h3 id="维果斯基文化历史理论-🔴🔴" tabindex="-1">维果斯基文化历史理论 🔴🔴 <a class="header-anchor" href="#维果斯基文化历史理论-🔴🔴" aria-label="Permalink to &quot;维果斯基文化历史理论 🔴🔴&quot;">​</a></h3><p><strong>核心概念</strong>：</p><ul><li><strong>最近发展区</strong> 🔴🔴🔴：学生现有水平与在成人指导下能达到的水平之间的差距</li><li><strong>教学应当走在发展前面</strong> 🔴🔴</li><li><strong>支架式教学</strong> 🔴：教师提供适当帮助，逐步撤去支架</li></ul><hr><h2 id="_5-2-中学生情绪与情感-🔴🔴" tabindex="-1">5.2 中学生情绪与情感 🔴🔴 <a class="header-anchor" href="#_5-2-中学生情绪与情感-🔴🔴" aria-label="Permalink to &quot;5.2 中学生情绪与情感 🔴🔴&quot;">​</a></h2><h3 id="情绪分类-🔴" tabindex="-1">情绪分类 🔴 <a class="header-anchor" href="#情绪分类-🔴" aria-label="Permalink to &quot;情绪分类 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>含义</th><th>特点</th><th>举例</th></tr></thead><tbody><tr><td>心境 🔴</td><td>微弱、持久的情绪状态</td><td>弥散性、长期性</td><td>人逢喜事精神爽</td></tr><tr><td>激情</td><td>强烈、短暂、爆发式</td><td>爆发性、冲动性</td><td>暴怒、狂喜</td></tr><tr><td>应激</td><td>紧急情况下的适应性反应</td><td>紧迫性、突发性</td><td>突遇地震的紧张反应</td></tr></tbody></table><h3 id="情感分类-🔴" tabindex="-1">情感分类 🔴 <a class="header-anchor" href="#情感分类-🔴" aria-label="Permalink to &quot;情感分类 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>含义</th><th>举例</th></tr></thead><tbody><tr><td>道德感</td><td>根据道德标准评价时产生的情感</td><td>爱国感、正义感、同情心</td></tr><tr><td>理智感</td><td>认识和追求真理过程中产生的情感</td><td>好奇心、求知欲、惊喜</td></tr><tr><td>美感</td><td>审美时产生的情感</td><td>对美的欣赏、感动</td></tr></tbody></table><h3 id="中学生情绪特点-🔴🔴" tabindex="-1">中学生情绪特点 🔴🔴 <a class="header-anchor" href="#中学生情绪特点-🔴🔴" aria-label="Permalink to &quot;中学生情绪特点 🔴🔴&quot;">​</a></h3><ol><li><strong>强烈性</strong> — 情绪反应强烈，易激动</li><li><strong>不稳定性</strong> — 情绪变化快，起伏大</li><li><strong>内隐性</strong> — 内心体验与外部表现不一致</li><li><strong>敏感性</strong> — 对外界刺激反应敏感</li></ol><h3 id="中学生情绪调节-🔴" tabindex="-1">中学生情绪调节 🔴 <a class="header-anchor" href="#中学生情绪调节-🔴" aria-label="Permalink to &quot;中学生情绪调节 🔴&quot;">​</a></h3><p><strong>常用方法</strong>：</p><ol><li>认知调节（改变认知方式）</li><li>合理宣泄（运动、倾诉）</li><li>转移注意</li><li>放松训练</li><li>积极心理暗示</li></ol><hr><h2 id="_5-3-中学生人格发展-🔴🔴" tabindex="-1">5.3 中学生人格发展 🔴🔴 <a class="header-anchor" href="#_5-3-中学生人格发展-🔴🔴" aria-label="Permalink to &quot;5.3 中学生人格发展 🔴🔴&quot;">​</a></h2><h3 id="埃里克森人格发展阶段-🔴🔴🔴" tabindex="-1">埃里克森人格发展阶段 🔴🔴🔴 <a class="header-anchor" href="#埃里克森人格发展阶段-🔴🔴🔴" aria-label="Permalink to &quot;埃里克森人格发展阶段 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>年龄</th><th>主要冲突</th><th>发展任务</th></tr></thead><tbody><tr><td>婴儿期</td><td>0-1.5岁</td><td>信任vs怀疑</td><td>建立信任</td></tr><tr><td>儿童早期</td><td>1.5-3岁</td><td>自主vs羞怯</td><td>自主性</td></tr><tr><td>学前期</td><td>3-6岁</td><td>主动vs内疚</td><td>主动性</td></tr><tr><td>学龄期</td><td>6-12岁</td><td>勤奋vs自卑</td><td>勤奋感</td></tr><tr><td>青春期 🔴🔴</td><td>12-18岁</td><td>同一性vs角色混乱</td><td>建立自我同一性</td></tr><tr><td>成年早期</td><td>18-30岁</td><td>亲密vs孤独</td><td>建立亲密关系</td></tr><tr><td>成年中期</td><td>30-60岁</td><td>繁殖vs停滞</td><td>关心下一代</td></tr><tr><td>成年晚期</td><td>60岁+</td><td>完善vs绝望</td><td>自我完善</td></tr></tbody></table><p><strong>中学生核心任务</strong> 🔴🔴🔴：建立自我同一性（知道自己是谁、要成为什么样的人）</p><h3 id="气质类型-🔴" tabindex="-1">气质类型 🔴 <a class="header-anchor" href="#气质类型-🔴" aria-label="Permalink to &quot;气质类型 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>特点</th><th>教育策略</th></tr></thead><tbody><tr><td>胆汁质</td><td>精力旺盛、直率热情、易冲动</td><td>培养自制力、耐心引导</td></tr><tr><td>多血质</td><td>活泼好动、反应迅速、善交际</td><td>培养专注力、恒心</td></tr><tr><td>黏液质</td><td>安静稳重、反应缓慢、踏实</td><td>鼓励参与、主动表达</td></tr><tr><td>抑郁质</td><td>敏感细腻、孤僻、多愁善感</td><td>多鼓励、避免公开批评</td></tr></tbody></table><h3 id="性格结构-🔴" tabindex="-1">性格结构 🔴 <a class="header-anchor" href="#性格结构-🔴" aria-label="Permalink to &quot;性格结构 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特征</th><th>含义</th><th>举例</th></tr></thead><tbody><tr><td>态度特征</td><td>对人对事的态度</td><td>诚实、谦虚、自私</td></tr><tr><td>意志特征</td><td>调节行为的方式</td><td>坚毅、果断、怯懦</td></tr><tr><td>情绪特征</td><td>情绪活动特点</td><td>乐观、易怒、冷静</td></tr><tr><td>理智特征</td><td>认知活动特点</td><td>深思熟虑、浅尝辄止</td></tr></tbody></table><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>口诀/要点</th></tr></thead><tbody><tr><td>皮亚杰四阶段</td><td>感前具形（感知运动→前运算→具体运算→形式运算）</td></tr><tr><td>最近发展区</td><td>现有水平与指导后水平之间的差距</td></tr><tr><td>中学生核心冲突</td><td>同一性vs角色混乱（12-18岁）</td></tr><tr><td>情绪三状态</td><td>心境（持久）+激情（爆发）+应激（紧急）</td></tr><tr><td>情感三类型</td><td>道德感+理智感+美感</td></tr></tbody></table>',36)])])}const g=d(h,[["render",o]]);export{u as __pageData,g as default};
